// src/components/Footer/index.jsx

import React from 'react';
import s from './Footer.module.css';

// 1. Импортируем PNG-файлы иконок
import PhoneIcon from '../assets/icons/ic-instagram.svg';
import ChatIcon from '../assets/icons/ic-whatsapp.svg';

// Данные для контакта (обновляем поле icon на пути к PNG)
const CONTACT_DATA = {
    phone: '+7 (499) 350-66-04',
    socials: [
        { id: 1, icon: PhoneIcon, label: 'Телефон' }, 
        { id: 2, icon: ChatIcon, label: 'Чат/WhatsApp' } 
    ],
    address: 'Dubininskaya Ulitsa, 96, Moscow, Russia, 115093',
    hours: '24 hours a day',
};

const Footer = () => {
    return (
        <footer className={s.footer}>
            <div className={s.container}>

                <div className={s.sectionHeader}>
                    <h2>Contact</h2>
                </div>

                <div className={s.infoGrid}>

                    {/* 1. Phone */}
                    <div className={s.infoCard}>
                        <p className={s.cardTitle}>Phone</p>
                        <h3 className={s.cardContent}>{CONTACT_DATA.phone}</h3>
                    </div>

                    {/* 2. Socials - ИСПОЛЬЗУЕМ ТЕГ <img> */}
                    <div className={s.infoCard}>
                        <p className={s.cardTitle}>Socials</p>
                        <div className={s.socialIcons}>
                            {CONTACT_DATA.socials.map(social => (
                                <div key={social.id} className={s.socialIcon} title={social.label}>
                                    {/* Заменяем {social.icon} на <img> */}
                                    <img 
                                        src={social.icon} 
                                        alt={social.label} 
                                        className={s.socialImage} 
                                    />
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 3. Address (Занимает 2 колонки) */}
                    <div className={`${s.infoCard} ${s.cardLarge}`}>
                        <p className={s.cardTitle}>Address</p>
                        <h3 className={s.cardContent}>{CONTACT_DATA.address}</h3>
                    </div>

                    {/* 4. Working Hours */}
                    <div className={s.infoCard}>
                        <p className={s.cardTitle}>Working Hours</p>
                        <h3 className={s.cardContent}>{CONTACT_DATA.hours}</h3>
                    </div>
                </div>

                {/* ... Блок для API-карты ... */}
                <div className={s.mapContainer}>
                    <div className={s.mapPlaceholder}>
                        Карта iThub college. <br/> (Интеграция API требуется)
                    </div>
                </div>
            </div>

            <div className={s.copyright}>
                <p>© {new Date().getFullYear()} Garden Store.</p>
            </div>
        </footer>
    );
};

export default Footer;
